const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

// Game configuration
const GRID_SIZE = 8;
const CELL_SIZE = 50;
const COLORS = [
    '#FF6B6B', // Red
    '#4ECDC4', // Teal
    '#45B7D1', // Blue
    '#FFA07A', // Orange
    '#98D8C8', // Green
    '#F7DC6F'  // Yellow
];

// Game state
let grid = [];
let score = 0;
let timeLeft = 60;
let combo = 1;
let gameRunning = true;
let particles = [];
let selectedCells = [];
let highScore = localStorage.getItem('colorMatchHighScore') || 0;

// Initialize grid
function initGrid() {
    grid = [];
    for (let row = 0; row < GRID_SIZE; row++) {
        grid[row] = [];
        for (let col = 0; col < GRID_SIZE; col++) {
            grid[row][col] = {
                color: COLORS[Math.floor(Math.random() * COLORS.length)],
                x: col * CELL_SIZE,
                y: row * CELL_SIZE,
                scale: 1,
                marked: false
            };
        }
    }
}

// Get connected cells of same color (flood fill)
function getConnectedCells(startRow, startCol) {
    const color = grid[startRow][startCol].color;
    const visited = new Set();
    const connected = [];
    const queue = [[startRow, startCol]];

    while (queue.length > 0) {
        const [row, col] = queue.shift();
        const key = `${row},${col}`;

        if (visited.has(key) || row < 0 || row >= GRID_SIZE || col < 0 || col >= GRID_SIZE) {
            continue;
        }

        if (grid[row][col].color !== color) {
            continue;
        }

        visited.add(key);
        connected.push({row, col});

        // Check neighbors
        queue.push([row - 1, col], [row + 1, col], [row, col - 1], [row, col + 1]);
    }

    return connected;
}

// Remove cells and apply gravity
function removeCells(cells) {
    // Create particles
    for (let cell of cells) {
        createParticles(cell.col * CELL_SIZE + CELL_SIZE/2, cell.row * CELL_SIZE + CELL_SIZE/2, grid[cell.row][cell.col].color);
    }

    // Mark for removal
    for (let cell of cells) {
        grid[cell.row][cell.col] = null;
    }

    // Apply gravity
    for (let col = 0; col < GRID_SIZE; col++) {
        let writeRow = GRID_SIZE - 1;
        for (let row = GRID_SIZE - 1; row >= 0; row--) {
            if (grid[row][col] !== null) {
                grid[writeRow][col] = grid[row][col];
                if (writeRow !== row) {
                    grid[row][col] = null;
                }
                writeRow--;
            }
        }

        // Fill empty spaces
        for (let row = writeRow; row >= 0; row--) {
            grid[row][col] = {
                color: COLORS[Math.floor(Math.random() * COLORS.length)],
                x: col * CELL_SIZE,
                y: row * CELL_SIZE,
                scale: 1,
                marked: false
            };
        }
    }

    // Calculate score
    const points = cells.length * cells.length * 10 * combo;
    score += points;
    combo = Math.min(combo + 1, 5);
    updateUI();
}

// Create explosion particles
function createParticles(x, y, color) {
    for (let i = 0; i < 8; i++) {
        particles.push({
            x: x,
            y: y,
            vx: (Math.random() - 0.5) * 200,
            vy: (Math.random() - 0.5) * 200,
            color: color,
            life: 1,
            size: Math.random() * 10 + 5
        });
    }
}

// Update particles
function updateParticles(dt) {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        p.vy += 300 * dt; // Gravity
        p.life -= dt * 2;

        if (p.life <= 0) {
            particles.splice(i, 1);
        }
    }
}

// Draw the game
function draw() {
    // Clear canvas
    ctx.fillStyle = '#1a1a2e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw grid cells
    for (let row = 0; row < GRID_SIZE; row++) {
        for (let col = 0; col < GRID_SIZE; col++) {
            if (grid[row][col]) {
                const cell = grid[row][col];
                ctx.save();
                ctx.translate(col * CELL_SIZE + CELL_SIZE/2, row * CELL_SIZE + CELL_SIZE/2);
                ctx.scale(cell.scale, cell.scale);
                ctx.translate(-CELL_SIZE/2, -CELL_SIZE/2);

                // Draw cell
                ctx.fillStyle = cell.color;
                ctx.fillRect(2, 2, CELL_SIZE - 4, CELL_SIZE - 4);

                // Highlight effect
                ctx.fillStyle = 'rgba(255,255,255,0.2)';
                ctx.fillRect(2, 2, CELL_SIZE - 4, CELL_SIZE/3);

                ctx.restore();
            }
        }
    }

    // Draw particles
    for (let p of particles) {
        ctx.save();
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }
}

// Handle mouse click
canvas.addEventListener('click', (e) => {
    if (!gameRunning) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const col = Math.floor(x / CELL_SIZE);
    const row = Math.floor(y / CELL_SIZE);

    if (row >= 0 && row < GRID_SIZE && col >= 0 && col < GRID_SIZE && grid[row][col]) {
        const connected = getConnectedCells(row, col);

        if (connected.length >= 3) {
            removeCells(connected);
        } else {
            // Too small - reset combo
            combo = 1;
            updateUI();
        }
    }
});

// Update UI
function updateUI() {
    document.getElementById('score').textContent = score;
    document.getElementById('time').textContent = timeLeft;
    document.getElementById('combo').textContent = combo;
}

// Game timer
function startTimer() {
    const timerInterval = setInterval(() => {
        if (!gameRunning) {
            clearInterval(timerInterval);
            return;
        }

        timeLeft--;
        updateUI();

        if (timeLeft <= 0) {
            endGame();
            clearInterval(timerInterval);
        }
    }, 1000);
}

// End game
function endGame() {
    gameRunning = false;

    if (score > highScore) {
        highScore = score;
        localStorage.setItem('colorMatchHighScore', highScore);
    }

    document.getElementById('final-score').textContent = score;
    document.getElementById('high-score').textContent = highScore;
    document.getElementById('game-over').style.display = 'block';
}

// Restart game
function restartGame() {
    score = 0;
    timeLeft = 60;
    combo = 1;
    gameRunning = true;
    particles = [];
    document.getElementById('game-over').style.display = 'none';
    initGrid();
    updateUI();
    startTimer();
}

// Game loop
let lastTime = 0;
function gameLoop(currentTime) {
    const dt = (currentTime - lastTime) / 1000;
    lastTime = currentTime;

    updateParticles(dt);
    draw();

    requestAnimationFrame(gameLoop);
}

// Initialize
initGrid();
updateUI();
startTimer();
requestAnimationFrame(gameLoop);
console.log('{{project_name}} started!');
